def partition_equal(arr):
   total = sum(arr) 
   if total % 2 != 0: 
      return False 
   half = total//2 
   n = len(arr) 
   dp = [[False for _ in range(half+1)] for _ in range(n+1)] 
   for i in range(n+1): 
      dp[i][0] = True 
   for j in range(1,half+1): 
      dp[0][j] = False 
   for i in range(1, n+1): 
      for j in range(1, half+1): 
         if arr[i-1] <= j:
            dp[i][j] = dp[i-1][j-arr[i-1]] or dp[i-1][j] 
         else:
            dp[i][j] = dp[i-1][j] 
   return dp[n][half]

