def isArmstrongNumber(num):

    order = len(str(num))
    result = 0

    # calculate the sum of nth power of every digit
    temp = num
    while(temp > 0):
        digit = temp % 10
        result += digit ** order
        temp //= 10

    # check if sum is equal to the given num
    if (result == num):
        return True
    else:
        return False

