class Stack:
    def __init__(self):
        self.head = None
        self.tail = self.head
        self.items = 0

    def push(self, data):
        new_node = Node(data)

        if self.head is None:
            self.head = new_node
        else:
            new_node.next = self.head
            self.head = new_node
        self.tail = self.head
        self.items +=1

    def pop(self):
        if self.head is None:
            return None

        data = self.head.data
        self.head = self.head.next
        self.items -= 1
        return data

